      interview: [
        { level: "Junior", q: "What is a VPC?", a: "A logically isolated section of the AWS Cloud where you can launch AWS resources in a virtual network that you define.", type: "Conceptual" },
        { level: "Junior", q: "What is a Subnet?", a: "A range of IP addresses in your VPC. You can launch AWS resources into a specified subnet.", type: "Conceptual" },
        { level: "Junior", q: "What is an Internet Gateway (IGW)?", a: "A horizontally scaled, redundant, and highly available VPC component that allows communication between your VPC and the internet.", type: "Conceptual" },
        { level: "Junior", q: "What is a NAT Gateway?", a: "A Network Address Translation service that allows instances in a private subnet to connect to the internet while preventing the internet from initiating a connection.", type: "Conceptual" },
        { level: "Junior", q: "What is a Route Table?", a: "A set of rules (routes) used to determine where network traffic from your subnet or gateway is directed.", type: "Conceptual" },
        { level: "Junior", q: "Public vs Private Subnet?", a: "A Public subnet has a route to an Internet Gateway. A Private subnet does not.", type: "Conceptual" },
        { level: "Junior", q: "What is a Security Group?", a: "A virtual firewall for your EC2 instance to control inbound and outbound traffic.", type: "Conceptual" },
        { level: "Junior", q: "What is a Network ACL (NACL)?", a: "An optional layer of security for your VPC that acts as a firewall for controlling traffic in and out of one or more subnets.", type: "Conceptual" },
        { level: "Junior", q: "What is VPC Peering?", a: "A networking connection between two VPCs that enables you to route traffic between them securely using private IP addresses.", type: "Conceptual" },
        { level: "Junior", q: "What is a 'local' route?", a: "A default route in every route table that allows instances in the same VPC to communicate with each other.", type: "Conceptual" },
        { level: "Junior", q: "What is CIDR?", a: "Classless Inter-Domain Routing. A method for describing a range of IP addresses (e.g., 10.0.0.0/16).", type: "Conceptual" },
        { level: "Junior", q: "What is a Bastion Host?", a: "A public-facing instance used as a jump server to access instances in private subnets via SSH or RDP.", type: "Conceptual" },
        { level: "Junior", q: "Can a VPC span multiple AZs?", a: "Yes, but a subnet is always tied to a single AZ.", type: "Conceptual" },
        { level: "Junior", q: "Difference between an Internet Gateway and a NAT Gateway?", a: "An Internet Gateway allows two-way traffic for public subnets. A NAT Gateway allows one-way outbound traffic for private subnets (updates etc).", type: "Conceptual" },
        { level: "Mid", q: "Explain Security Groups vs Network ACLs.", a: "SG are stateful and operate at the instance level. NACL are stateless and operate at the subnet level.", type: "Conceptual" },
        { level: "Mid", q: "What is VPC Peering?", a: "A networking connection between two VPCs that enables you to route traffic between them using private IPv4/IPv6 addresses.", type: "Conceptual" },
        { level: "Mid", q: "What is a Bastion Host?", a: "A specially configured server in a public subnet used to provide secure access to instances in a private subnet, usually via SSH.", type: "Conceptual" },
        { level: "Mid", q: "How do you connect your VPC to S3 privately?", a: "By using a VPC Endpoint (Interface or Gateway type), which avoids routing traffic over the public internet.", type: "Scenario" },
        { level: "Mid", q: "Explain 'Egress-Only Internet Gateway'.", a: "Essentially a NAT Gateway but for IPv6 traffic, allowing outbound connectivity only.", type: "Conceptual" },
        { level: "Mid", q: "How do you troubleshoot a 'Connection Refused' error in a VPC?", a: "Check Security Group rules, NACL rules, and verify the service is actually listening on the correct port on the instance.", type: "Scenario" },
        { level: "Mid", q: "What are 'VPC Flow Logs' useful for?", a: "Troubleshooting why specific traffic is being reached or dropped and for security auditing.", type: "Conceptual" },
        { level: "Mid", q: "Difference between Gateway Endpoints and Interface Endpoints?", a: "Gateway Endpoints are free and target S3/DynamoDB via Route Table. Interface Endpoints use an ENI (private IP) and cost money for most other services.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'Secondary CIDR Blocks'.", a: "Allowing a VPC to have more IP space if the primary CIDR block is exhausted.", type: "Conceptual" },
        { level: "Mid", q: "How do you implement 'High Availability' for NAT Gateways?", a: "By placing a NAT Gateway in each AZ and directing the local private subnet traffic to the NAT Gateway in the same AZ.", type: "Scenario" },
        { level: "Mid", q: "What is 'Direct Connect'?", a: "A dedicated physical network connection from your on-premises data center to AWS.", type: "Conceptual" },
        { level: "Mid", q: "What is the 'Transit Gateway' intended for?", a: "Simplifying mesh networking between many VPCs and on-premises sites by acting as a central hub.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle 'IP Overlap' in VPC Peering?", a: "You cannot peer VPCs with overlapping CIDR blocks; you'd need to use PrivateLink or Transit Gateway with NAT.", type: "Scenario" },
        { level: "Senior", q: "Explain CIDR notation.", a: "Classless Inter-Domain Routing. A method for allocating IP addresses and IP routing (e.g., 10.0.0.0/16 specifies a range of 65,536 addresses).", type: "Conceptual" },
        { level: "Senior", q: "What is a VPC Flow Log?", a: "A feature that enables you to capture information about the IP traffic going to and from network interfaces in your VPC.", type: "Conceptual" },
        { level: "Senior", q: "How would you design a highly available VPC architecture?", a: "By spanning multiple AZs, placing redundant NAT Gateways in each AZ, and using an ELB (Elastic Load Balancer) to distribute traffic.", type: "Scenario" },
        { level: "Senior", q: "What is the Transit Gateway?", a: "A hub that connects multiple VPCs and on-premises networks together, simplifying complex network architectures.", type: "Conceptual" },
        { level: "Senior", q: "Explain the difference between Site-to-Site VPN and AWS Direct Connect.", a: "VPN is inexpensive but uses the public internet (higher latency). Direct Connect is a physical cable (lower latency, high cost, more secure).", type: "Scenario" },
        { level: "Senior", q: "How would you implement 'Global Traffic Management' for a multi-region app?", a: "Using Route 53 Geolocation or Latency-based routing to direct users to the closest healthy region's ALB/NLB.", type: "Scenario" },
        { level: "Senior", q: "Explain 'VPC PrivateLink' benefits.", a: "Allows exposing a service to thousands of VPCs without peering or traffic traversing the public internet, using ENIs.", type: "Conceptual" },
        { level: "Senior", q: "How do you secure 'North-South' traffic in a VPC?", a: "Using an Internet Gateway for exit/entry and inspecting traffic with a Network Firewall or third-party IDS/IPS appliance.", type: "Scenario" },
        { level: "Senior", q: "How do you secure 'East-West' traffic?", a: "Using Security Groups to enforce micro-segmentation between application tiers and services.", type: "Scenario" },
        { level: "Senior", q: "What is 'BYOIP' and why use it?", a: "Bring Your Own IP - moving your own IP ranges to AWS to keep allow-lists active or for reputation-based emailing.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Gateway Load Balancer' (GWLB) architecture.", a: "Intercepting traffic from an IGW or between subnets and routing it to an appliance for deep packet inspection using GENEVE protocol.", type: "Conceptual" },
        { level: "Senior", q: "How do you implement 'IP Address Management' (IPAM) at scale?", a: "Using AWS VPC IPAM to centrally plan, track, and monitor IP addresses across multiple VPCs and accounts.", type: "Scenario" },
        { level: "Senior", q: "Explain 'IPv6 adaptation' strategies for existing VPCs.", a: "Adding dual-stack subnets, using Egress-only IGWs, and ensuring ALBs are configured for dual-stack support.", type: "Scenario" },
        { level: "Senior", q: "How would you handle 'Network Isolation' for a high-security workload?", a: "Placing it in a private subnet with NO internet gateway, NO NAT gateway, and only using VPC Endpoints for necessary AWS services.", type: "Scenario" },
        { level: "Senior", q: "What is 'VPC Lattice' exactly?", a: "It abstracts networking complexity by providing a consistent way to handle discovery, connectivity, and observability for services across accounts and VPCs.", type: "Conceptual" }
      ]
